import { useEffect } from 'react';

interface ImagePreloaderProps {
  images: string[];
  priority?: boolean;
}

export const ImagePreloader = ({ images, priority = false }: ImagePreloaderProps) => {
  useEffect(() => {
    if (!priority && images.length > 3) {
      // For non-priority images, preload only the first few to avoid blocking
      return;
    }

    const preloadImages = images.slice(0, priority ? images.length : 3);
    
    preloadImages.forEach((src) => {
      const link = document.createElement('link');
      link.rel = 'preload';
      link.as = 'image';
      link.href = src;
      link.crossOrigin = 'anonymous';
      document.head.appendChild(link);
    });

    // Cleanup function to remove preload links when component unmounts
    return () => {
      preloadImages.forEach((src) => {
        const existingLink = document.querySelector(`link[href="${src}"]`);
        if (existingLink) {
          document.head.removeChild(existingLink);
        }
      });
    };
  }, [images, priority]);

  return null;
};

// Hook for programmatic image preloading
export const useImagePreloader = () => {
  const preloadImage = (src: string): Promise<void> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve();
      img.onerror = reject;
      img.src = src;
    });
  };

  const preloadImages = async (sources: string[]): Promise<void[]> => {
    return Promise.all(sources.map(preloadImage));
  };

  return { preloadImage, preloadImages };
};

import { useEffect, useState } from 'react';

interface PerformanceMetrics {
  lcp: number | null;
  fid: number | null;
  cls: number | null;
  ttfb: number | null;
}

export const usePerformanceMetrics = () => {
  const [metrics, setMetrics] = useState<PerformanceMetrics>({
    lcp: null,
    fid: null,
    cls: null,
    ttfb: null,
  });

  useEffect(() => {
    // Measure Core Web Vitals
    const measureLCP = () => {
      if ('PerformanceObserver' in window) {
        const observer = new PerformanceObserver((list) => {
          const entries = list.getEntries();
          const lastEntry = entries[entries.length - 1];
          setMetrics(prev => ({ ...prev, lcp: lastEntry.startTime }));
        });
        observer.observe({ entryTypes: ['largest-contentful-paint'] });
      }
    };

    const measureFID = () => {
      if ('PerformanceObserver' in window) {
        const observer = new PerformanceObserver((list) => {
          const entries = list.getEntries();
          entries.forEach((entry: any) => {
            setMetrics(prev => ({ ...prev, fid: entry.processingStart - entry.startTime }));
          });
        });
        observer.observe({ entryTypes: ['first-input'] });
      }
    };

    const measureCLS = () => {
      if ('PerformanceObserver' in window) {
        let clsValue = 0;
        const observer = new PerformanceObserver((list) => {
          const entries = list.getEntries();
          entries.forEach((entry: any) => {
            if (!entry.hadRecentInput) {
              clsValue += entry.value;
            }
          });
          setMetrics(prev => ({ ...prev, cls: clsValue }));
        });
        observer.observe({ entryTypes: ['layout-shift'] });
      }
    };

    const measureTTFB = () => {
      if ('PerformanceObserver' in window) {
        const observer = new PerformanceObserver((list) => {
          const entries = list.getEntries();
          entries.forEach((entry: any) => {
            if (entry.name === document.location.href) {
              setMetrics(prev => ({ ...prev, ttfb: entry.responseStart - entry.requestStart }));
            }
          });
        });
        observer.observe({ entryTypes: ['navigation'] });
      }
    };

    measureLCP();
    measureFID();
    measureCLS();
    measureTTFB();
  }, []);

  return metrics;
};

// Development-only performance monitor
export const PerformanceMonitor = () => {
  const metrics = usePerformanceMetrics();

  if (process.env.NODE_ENV !== 'development') {
    return null;
  }

  return (
    <div className="fixed bottom-4 left-4 z-50 bg-black/80 text-white p-3 rounded-lg text-xs font-mono">
      <div className="space-y-1">
        <div>LCP: {metrics.lcp ? `${Math.round(metrics.lcp)}ms` : 'Measuring...'}</div>
        <div>FID: {metrics.fid ? `${Math.round(metrics.fid)}ms` : 'Waiting...'}</div>
        <div>CLS: {metrics.cls ? metrics.cls.toFixed(3) : 'Measuring...'}</div>
        <div>TTFB: {metrics.ttfb ? `${Math.round(metrics.ttfb)}ms` : 'Measuring...'}</div>
      </div>
    </div>
  );
};

import { useEffect, useRef } from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar } from 'react-chartjs-2';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

export const SkillsChart = () => {
  const chartRef = useRef<ChartJS<"bar", number[], string>>(null);

  const skillsData = {
    labels: [
      'Product Design',
      'UX/UI Design', 
      'User Research',
      'Info. Architecture',
      'Interaction Design',
      'Systems Thinking',
      'Data-Informed Design'
    ],
    datasets: [{
      label: 'Proficiency',
      data: [95, 90, 85, 80, 85, 90, 85],
      borderWidth: 1,
    }]
  };

  const getChartColors = () => {
    const style = getComputedStyle(document.documentElement);
    const isDark = !document.body.classList.contains('light');
    
    return {
      backgroundColor: 'rgba(255, 71, 87, 0.6)',
      borderColor: '#ff4757',
      textColor: isDark ? '#a0a0a0' : '#4b5563',
      gridColor: isDark ? 'rgba(255, 255, 255, 0.1)' : 'rgba(0, 0, 0, 0.1)'
    };
  };

  const updateChartColors = () => {
    if (chartRef.current) {
      const colors = getChartColors();
      const chart = chartRef.current;
      
      chart.data.datasets[0].backgroundColor = colors.backgroundColor;
      chart.data.datasets[0].borderColor = colors.borderColor;
      
      if (chart.options.scales?.x?.ticks) {
        chart.options.scales.x.ticks.color = colors.textColor;
      }
      if (chart.options.scales?.y?.ticks) {
        chart.options.scales.y.ticks.color = colors.textColor;
      }
      if (chart.options.scales?.x?.grid) {
        chart.options.scales.x.grid.color = colors.gridColor;
      }
      if (chart.options.scales?.y?.grid) {
        chart.options.scales.y.grid.color = colors.gridColor;
      }
      
      chart.update();
    }
  };

  useEffect(() => {
    updateChartColors();
    
    // Listen for theme changes
    const observer = new MutationObserver(updateChartColors);
    observer.observe(document.body, {
      attributes: true,
      attributeFilter: ['class']
    });

    return () => observer.disconnect();
  }, []);

  const options = {
    indexAxis: 'y' as const,
    responsive: true,
    maintainAspectRatio: false,
    scales: {
      x: {
        beginAtZero: true,
        max: 100,
        ticks: {
          color: getChartColors().textColor,
        },
        grid: {
          color: getChartColors().gridColor,
        }
      },
      y: {
        ticks: {
          color: getChartColors().textColor,
        },
        grid: {
          color: getChartColors().gridColor,
        }
      }
    },
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        callbacks: {
          label: function(context: any) {
            return `${context.parsed.x}% proficiency`;
          }
        }
      }
    }
  };

  return (
    <div className="chart-container p-4 md:p-6 rounded-lg shadow-md">
      <Bar ref={chartRef} data={skillsData} options={options} />
    </div>
  );
};

import { useState, useEffect, useCallback } from 'react';

const LoadingSpinner = () => (
  <div className="flex items-center justify-center h-full">
    <div className="text-center">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
      <p className="text-text-secondary">Loading 3D Scene...</p>
    </div>
  </div>
);

const ErrorFallback = ({ onRetry }: { onRetry: () => void }) => (
  <div className="flex flex-col items-center justify-center h-full text-center p-6">
    <div className="mb-4">
      <div className="w-16 h-16 bg-yellow-500/20 rounded-full flex items-center justify-center mx-auto mb-2">
        <span className="text-2xl">🎨</span>
      </div>
      <p className="text-text-secondary">3D Scene Unavailable</p>
      <p className="text-xs text-text-secondary/60 mt-1">Interactive content will load here</p>
    </div>
    <button 
      onClick={onRetry}
      className="px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90 transition-colors text-sm"
    >
      Try Again
    </button>
  </div>
);

export const Spline3DObject = ({ mousePosition }: { mousePosition?: { x: number; y: number } }) => {
  const [SplineComponent, setSplineComponent] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [hasError, setHasError] = useState(false);
  const [key, setKey] = useState(0);
  const [splineInstance, setSplineInstance] = useState<any>(null);

  const loadSpline = useCallback(async () => {
    try {
      setIsLoading(true);
      setHasError(false);
      
      const SplineModule = await import('@splinetool/react-spline');
      setSplineComponent(() => SplineModule.default);
    } catch (error) {
      console.warn('Spline module failed to load:', error);
      setHasError(true);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Update spline rotation based on mouse position
  useEffect(() => {
    if (splineInstance && mousePosition) {
      const x = (mousePosition.x / window.innerWidth) * 2 - 1;
      const y = -(mousePosition.y / window.innerHeight) * 2 + 1;
      
      if (splineInstance.scene && splineInstance.scene.children[0]) {
        const object = splineInstance.scene.children[0];
        object.rotation.y = x * 0.2;
        object.rotation.x = y * 0.1;
      }
    }
  }, [mousePosition, splineInstance]);

  useEffect(() => {
    loadSpline();
  }, [loadSpline]);

  const handleRetry = useCallback(() => {
    setKey(prev => prev + 1);
    loadSpline();
  }, [loadSpline]);

  const handleSplineError = useCallback(() => {
    setHasError(true);
  }, []);

  const handleSplineLoad = useCallback((spline: any) => {
    setSplineInstance(spline);
    
    // Zoom out the camera much further to show the complete scene
    if (spline.camera) {
      spline.camera.position.set(0, 0, 25); // Move camera much further back
      spline.camera.fov = 45; // Reduce field of view for more zoom out effect
    }
  }, []);

  const renderContent = () => {
    if (isLoading) {
      return <LoadingSpinner />;
    }

    if (hasError || !SplineComponent) {
      return <ErrorFallback onRetry={handleRetry} />;
    }

    return (
      <SplineComponent
        key={key}
        scene="https://prod.spline.design/uJ3Nbv7ycIMoKBoq/scene.splinecode"
        style={{ width: '100%', height: '100%' }}
        onError={handleSplineError}
        onLoad={handleSplineLoad}
      />
    );
  };

  return (
    <div className="reveal-on-scroll rounded-xl overflow-hidden bg-card h-[320px] w-full">
      {renderContent()}
    </div>
  );
};

